class Solution {
    static int idx = 0;

    public static void preorder(Node root, StringBuilder sb) {
        if (root == null) {
            sb.append("null ");
            return;
        }
        sb.append(root.data + " ");
        preorder(root.left, sb);
        preorder(root.right, sb);
    }

    public static String serialize(Node root) {
        if (root == null) {
            return "";
        }
        StringBuilder sb = new StringBuilder();
        preorder(root, sb);
        return sb.toString();
    }

    public static Node deserialization(String[] str) {
        if (idx >= str.length || str[idx].equals("null")) {
            idx++;
            return null;
        }
        Node root = new Node(Integer.parseInt(str[idx++]));
        root.left = deserialization(str);
        root.right = deserialization(str);
        return root;
    }

    public static Node deserialize(String data) {
        if (data == "") {
            return null;
        }
        String[] str = data.split(" ");
        return deserialization(str);
    }
}

