public:
    string serialize(Node* root) {
        if (!root) {
            return "";
        }
        queue<Node*> q;
        stringstream ss;
        q.push(root);

        while (!q.empty()) {
            Node* curr = q.front();
            q.pop();

            if (curr == nullptr) {
                ss << "n ";
                continue;
            }

            ss << curr->data << " ";
            q.push(curr->left);
            q.push(curr->right);
        }
        return ss.str();
    }

    Node* deserialize(string& data) {
        if (data.empty()) {
            return nullptr;
        }
        stringstream ss(data);
        string val;
        vector<string> nodes;

        while (ss >> val) {
            nodes.push_back(val);
        }

        Node* root = new Node(stoi(nodes[0]));
        queue<Node*> q;
        q.push(root);
        int i = 1;

        while (i < nodes.size()) {
            Node* parent = q.front();
            q.pop();

            if (nodes[i] != "n") {
                parent->left = new Node(stoi(nodes[i]));
                q.push(parent->left);
            }
            i++;

            if (i < nodes.size() && nodes[i] != "n") {
                parent->right = new Node(stoi(nodes[i]));
                q.push(parent->right);
            }
            i++;
        }
        return root;
    }
};

