class Solution {
    public static String serialize(Node root) {
        if (root == null) {
            return "";
        }
        Queue<Node> q = new LinkedList<>();
        StringBuilder sb = new StringBuilder();
        q.add(root);

        while (!q.isEmpty()) {
            Node curr = q.poll();

            if (curr == null) {
                sb.append("n ");
                continue;
            }

            sb.append(curr.data + " ");
            q.add(curr.left);
            q.add(curr.right);
        }
        return sb.toString();
    }

    public static Node deserialize(String data) {
        if (data == "") {
            return null;
        }
        String[] str = data.split(" ");
        Node root = new Node(Integer.parseInt(str[0]));
        Queue<Node> q = new LinkedList<>();
        q.add(root);

        for (int i = 1; i < str.length; i++) {
            Node parent = q.poll();

            if (!str[i].equals("n")) {
                Node left = new Node(Integer.parseInt(str[i]));
                parent.left = left;
                q.add(left);
            }

            if (!str[++i].equals("n")) {
                Node right = new Node(Integer.parseInt(str[i]));
                parent.right = right;
                q.add(right);
            }
        }
        return root;
    }
}

