class Solution {
    static serialize(node, treeStr) {
        if (node === null) {
            treeStr.push("#");
            return;
        }

        treeStr.push("^");
        treeStr.push(String(node.data));
        Solution.serialize(node.left, treeStr);
        Solution.serialize(node.right, treeStr);
    }

    static kmp(needle, haystack) {
        const m = needle.length;
        const n = haystack.length;

        if (n < m) {
            return false;
        }

        const lps = new Array(m).fill(0);
        let prev = 0;
        let i = 1;

        while (i < m) {
            if (needle[i] === needle[prev]) {
                prev += 1;
                lps[i] = prev;
                i += 1;
            } else {
                if (prev === 0) {
                    lps[i] = 0;
                    i += 1;
                } else {
                    prev = lps[prev - 1];
                }
            }
        }

        let haystackPointer = 0;
        let needlePointer = 0;

        while (haystackPointer < n) {
            if (haystack[haystackPointer] === needle[needlePointer]) {
                needlePointer += 1;
                haystackPointer += 1;
                if (needlePointer === m) {
                    return true;
                }
            } else {
                if (needlePointer === 0) {
                    haystackPointer += 1;
                } else {
                    needlePointer = lps[needlePointer - 1];
                }
            }
        }

        return false;
    }

    static isSubtree(root, subRoot) {
        const rootList = [];
        Solution.serialize(root, rootList);
        const r = rootList.join("");

        const subRootList = [];
        Solution.serialize(subRoot, subRootList);
        const s = subRootList.join("");

        return Solution.kmp(s, r);
    }
}

