#include <bits/stdc++.h>
using namespace std;

class Node {
public:
    unordered_map<char, Node*> children;
    string word;

    Node() : word("") {}
};

class solution {
public:
    vector<string> result;

    void backtrack(int row, int col, Node* parent, vector<vector<char>>& board) {
        char letter = board[row][col];
        Node* currNode = parent->children[letter];

        if (!currNode->word.empty()) {
            result.push_back(currNode->word);
            currNode->word.clear();
        }

        board[row][col] = '#';
        int dirs[4][2] = {{-1, 0}, {0, 1}, {1, 0}, {0, -1}};

        for (auto& dir : dirs) {
            int newRow = row + dir[0];
            int newCol = col + dir[1];

            if (newRow >= 0 && newRow < board.size() &&
                newCol >= 0 && newCol < board[0].size() &&
                currNode->children.count(board[newRow][newCol])) {
                backtrack(newRow, newCol, currNode, board);
            }
        }

        board[row][col] = letter;

        if (currNode->children.empty()) {
            parent->children.erase(letter);
        }
    }

    vector<string> searchSecretCodes(vector<vector<char>>& board, vector<string>& words) {
        result.clear();
        Node* root = new Node();

        for (const string& word : words) {
            Node* node = root;
            for (char ch : word) {
                if (!node->children.count(ch)) {
                    node->children[ch] = new Node();
                }
                node = node->children[ch];
            }
            node->word = word;
        }

        int n = board.size(), m = board[0].size();
        for (int row = 0; row < n; ++row) {
            for (int col = 0; col < m; ++col) {
                if (root->children.count(board[row][col])) {
                    backtrack(row, col, root, board);
                }
            }
        }

        if(result.size() == 0){
            return {"[]"};
        }
        return result;
    }
};

