class Node:
    def __init__(self):
        self.children = {}
        self.word = None


class solution:
    def __init__(self):
        self.result = []

    def backtrack(self, row, col, parent, board):
        letter = board[row][col]
        currNode = parent.children[letter]

        if currNode.word:
            self.result.append(currNode.word)
            currNode.word = None

        board[row][col] = '#'

        for dr, dc in [(-1, 0), (0, 1), (1, 0), (0, -1)]:
            newRow = row + dr
            newCol = col + dc

            if 0 <= newRow < len(board) and 0 <= newCol < len(board[0]) and board[newRow][newCol] in currNode.children:
                self.backtrack(newRow, newCol, currNode, board)

        board[row][col] = letter

        if not currNode.children:
            parent.children.pop(letter)

    def searchSecretCodes(self, board, words):
        self.result.clear()
        root = Node()

        for word in words:
            node = root
            for ch in word:
                if ch not in node.children:
                    node.children[ch] = Node()
                node = node.children[ch]
            node.word = word

