import java.util.*;

class Node {
    HashMap<Character, Node> children = new HashMap<>();
    String word = null;
}

class Solution {
    static char[][] boardRef = null;
    static ArrayList<String> result = new ArrayList<>();

    public static void backtrack(int row, int col, Node parent) {
        char letter = boardRef[row][col];
        Node currNode = parent.children.get(letter);

        if (currNode.word != null) {
            result.add(currNode.word);
            currNode.word = null;
        }

        boardRef[row][col] = '#';
        int[] rowOffset = {-1, 0, 1, 0};
        int[] colOffset = {0, 1, 0, -1};

        for (int i = 0; i < 4; ++i) {
            int newRow = row + rowOffset[i];
            int newCol = col + colOffset[i];

            if (newRow < 0 || newRow >= boardRef.length || newCol < 0 || newCol >= boardRef[0].length) {
                continue;
            }

            if (currNode.children.containsKey(boardRef[newRow][newCol])) {
                backtrack(newRow, newCol, currNode);
            }
        }

        boardRef[row][col] = letter;

        if (currNode.children.isEmpty()) {
            parent.children.remove(letter);
        }
    }

    public static List<String> searchSecretCodes(char[][] board, String[] words) {
        result.clear();
        Node root = new Node();

        for (String word : words) {
            Node node = root;
            for (char letter : word.toCharArray()) {
                if (node.children.containsKey(letter)) {
                    node = node.children.get(letter);
                } else {
                    Node newNode = new Node();
                    node.children.put(letter, newNode);
                    node = newNode;
                }
            }
            node.word = word;
        }

        boardRef = board;

        for (int row = 0; row < board.length; ++row) {
            for (int col = 0; col < board[row].length; ++col) {
                if (root.children.containsKey(board[row][col])) {
                    backtrack(row, col, root);
                }
            }
        }

        if(result.isEmpty()){
            return Arrays.asList("[]");
        }
        return result;
    }
}

