class Node {
    constructor() {
        this.children = new Map();
        this.word = "";
    }
}

class Solution {
    static backtrack(row, col, parent, board, result) {
        const letter = board[row][col];
        const currNode = parent.children.get(letter);

        if (currNode.word !== "") {
            result.push(currNode.word);
            currNode.word = "";
        }

        board[row][col] = "#";
        const dirs = [[-1, 0], [0, 1], [1, 0], [0, -1]];

        for (const [dr, dc] of dirs) {
            const newRow = row + dr;
            const newCol = col + dc;

            if (
                newRow >= 0 &&
                newRow < board.length &&
                newCol >= 0 &&
                newCol < board[0].length &&
                currNode.children.has(board[newRow][newCol])
            ) {
                Solution.backtrack(newRow, newCol, currNode, board, result);
            }
        }

        board[row][col] = letter;

        if (currNode.children.size === 0) {
            parent.children.delete(letter);
        }
    }

    static searchSecretCodes(board, words) {
        const result = [];
        const root = new Node();

        for (const word of words) {
            let node = root;
            for (const ch of word) {
                if (!node.children.has(ch)) {
                    node.children.set(ch, new Node());
                }
                node = node.children.get(ch);
            }
            node.word = word;
        }

        const n = board.length;
        const m = board[0].length;

        for (let row = 0; row < n; row++) {
            for (let col = 0; col < m; col++) {
                if (root.children.has(board[row][col])) {
                    Solution.backtrack(row, col, root, board, result);
                }
            }
        }

        if (result.length === 0) {
            return ["[]"];
        }
        return result;
    }
}

