fruitsBaskets(tree) {
    n = size(tree)                                           
    ans = 0 /*--- Initialize the answer to store longest sequence ---*/

    for i = 0 to n-1: /*--- Iterate over the array ---*/
        m = map<int,int> /*--- Initialize a map to track fruit types ---*/

        for j = i to n-1: /*--- Iterate from current position to end ---*/
            m[tree[j]]++ /*--- Add the fruit type to the map ---*/

            if size(m) > 2: /*--- Check if more than 2 types of fruits are in baskets ---*/
                break /*--- Stop if more than 2 types are collected ---*/

            ans = max(ans, j - i + 1) /*--- Update the maximum number of fruits collected ---*/

    return ans /*--- Return the maximum number of fruits that can be collected ---*/
}
