    n = size(tree)                          
    i = 0, j = 0, ans = 0 /*--- Initialize two pointers and answer ---*/
    m = map<int,int> /*--- Initialize a map to track fruit types ---*/

    while j < n: /*--- Traverse through the array ---*/
        m[tree[j]]++ /*--- Add fruit type at j to the map ---*/

