            i++ /*--- Move the left pointer ---*/

        ans = max(ans, j - i + 1) /*--- Update the longest sequence ---*/
        j++ /*--- Move the right pointer ---*/

    return ans /*--- Return the maximum number of fruits collected ---*/
}
