using namespace std;

class solution {
public:
    int fruitsBaskets(vector<int>& tree) {
        int n = tree.size();
        int i = 0, j = 0, ans = 0;
        unordered_map<int, int> m;

        while (j < n) {
            m[tree[j]]++;
            while (m.size() > 2) {
                m[tree[i]]--;
                if (m[tree[i]] == 0) {
                    m.erase(tree[i]);
                }
                i++;
            }
            ans = max(ans, j - i + 1);
            j++;
        }
        return ans;
    }
