using namespace std;

class solution {
public:
    int countSubarrays(vector<int>& arr, int k) {
        unordered_map<int, int> prefixSumMap;
        prefixSumMap[0] = 1;

        int currentSum = 0;
        int ans = 0;

        for (int num : arr) {
            currentSum += num;

            if (prefixSumMap.find(currentSum - k) != prefixSumMap.end()) {
                ans += prefixSumMap[currentSum - k];
            }

            prefixSumMap[currentSum]++;
        }

        return ans;
    }
};

