#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    vector<int> nextGreaterElementII(vector<int>& arr) {
        int n = arr.size();
        stack<int> stk;
        vector<int> ans(n, -1);

        for (int i = 2 * n - 1; i >= 0; i--) {
            while (!stk.empty() && arr[i % n] >= stk.top()) {
                stk.pop();
            }
            if (i < n && !stk.empty()) {
                ans[i] = stk.top();
            }
            stk.push(arr[i % n]);
        }

        return ans;
    }
};

