/* Use contribution counting to add all maximum contributions and subtract all minimum contributions */
sumOfSubarrayRanges(arr) {

    /* Store the size of the array for later calculations */
    n = arr.size()

    /* Create arrays to hold next and previous smaller and greater positions */
    nse[n]
    pse[n]
    nge[n]
    pge[n]

    /* Create an empty stack to maintain monotonic order during scans */
    stk

    /* Traverse from right to left to find the next smaller element for each position */
    for i = n - 1 to 0 {

        /* Remove indices that cannot serve as the next smaller element */
        while !stk.empty() && arr[stk.top()] >= arr[i] {
            stk.pop()
        }

        /* Store the next smaller position, or n if none exists */
        if stk.empty() {
            nse[i] = n
        }
        else {
            nse[i] = stk.top()
        }

        /* Push the current index for future elements on the left */
        stk.push(i)
    }

    /* Clear the stack before computing a different boundary */
    while !stk.empty() {
        stk.pop()
    }

    /* Traverse from left to right to find the previous smaller element for each position */
    for i = 0 to n - 1 {

        /* Remove indices that are strictly greater because they cannot remain previous smaller elements */
        while !stk.empty() && arr[stk.top()] > arr[i] {
            stk.pop()
        }

        /* Store the previous smaller position, or -1 if none exists */
        if stk.empty() {
            pse[i] = -1
        }
        else {
            pse[i] = stk.top()
        }

        /* Push the current index for future elements on the right */
        stk.push(i)
    }

    /* Clear the stack before computing greater boundaries */
    while !stk.empty() {
        stk.pop()
    }

    /* Traverse from right to left to find the next greater element for each position */
    for i = n - 1 to 0 {

        /* Remove indices that cannot serve as the next greater element */
        while !stk.empty() && arr[stk.top()] <= arr[i] {
            stk.pop()
        }

        /* Store the next greater position, or n if none exists */
        if stk.empty() {
            nge[i] = n
        }
        else {
            nge[i] = stk.top()
        }

        /* Push the current index for future elements on the left */
        stk.push(i)
    }

    /* Clear the stack before computing the last boundary */
    while !stk.empty() {
        stk.pop()
    }

    /* Traverse from left to right to find the previous greater element for each position */
    for i = 0 to n - 1 {

        /* Remove indices that are strictly smaller because they cannot remain previous greater elements */
        while !stk.empty() && arr[stk.top()] < arr[i] {
            stk.pop()
        }

        /* Store the previous greater position, or -1 if none exists */
        if stk.empty() {
            pge[i] = -1
        }
        else {
            pge[i] = stk.top()
        }

        /* Push the current index for future elements on the right */
        stk.push(i)
    }

    /* Start the answer at zero before adding all element contributions */
    sum = 0

    /* Add each element as a maximum contribution and subtract it as a minimum contribution */
    for i = 0 to n - 1 {
        sum = sum + ((nge[i] - i) * (i - pge[i]) - (nse[i] - i) * (i - pse[i])) * arr[i]
    }

    /* Return the final sum of all subarray ranges */
    return sum
}
