class Solution {
    static class Pair {
        Node node;
        int row;
        int col;

        Pair(Node node, int row, int col) {
            this.node = node;
            this.row = row;
            this.col = col;
        }
    }

    public static List<List<Integer>> verticalOrderTraversal(Node root) {
        List<List<Integer>> ans = new ArrayList<>();
        if (root == null) {
            return ans;
        }

        TreeMap<Integer, TreeMap<Integer, List<Integer>>> m = new TreeMap<>();
        Queue<Pair> q = new ArrayDeque<>();
        q.add(new Pair(root, 0, 0));

        while (!q.isEmpty()) {
            Pair front = q.poll();
            Node cur = front.node;
            int row = front.row;
            int col = front.col;

            m.putIfAbsent(col, new TreeMap<>());
            m.get(col).putIfAbsent(row, new ArrayList<>());
            m.get(col).get(row).add(cur.data);

            if (cur.left != null) {
                q.add(new Pair(cur.left, row + 1, col - 1));
            }
            if (cur.right != null) {
                q.add(new Pair(cur.right, row + 1, col + 1));
            }
        }

        for (Map.Entry<Integer, TreeMap<Integer, List<Integer>>> colEntry : m.entrySet()) {
            List<Integer> temp1 = new ArrayList<>();

            for (Map.Entry<Integer, List<Integer>> rowEntry : colEntry.getValue().entrySet()) {
                List<Integer> temp2 = new ArrayList<>(rowEntry.getValue());
                Collections.sort(temp2);
                temp1.addAll(temp2);
            }

            ans.add(temp1);
        }

        return ans;
    }
}

