            dfs(r + 1, c, grid, visited);
        }

        if (c > 0 && !visited[r][c - 1] && grid[r][c - 1] == 1) {
            dfs(r, c - 1, grid, visited);
        }

        if (c + 1 < n && !visited[r][c + 1] && grid[r][c + 1] == 1) {
            dfs(r, c + 1, grid, visited);
        }
    }

