import java.util.*;

class Solution {
    public static int rottenOranges(int[][] matrix) {
        int m = matrix.length;
        int n = matrix[0].length;
        Queue<int[]> q = new LinkedList<>();
        boolean[][] visited = new boolean[m][n];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (matrix[i][j] == 2) {
                    q.offer(new int[]{i, j, 0});
                    visited[i][j] = true;
                }
            }
        }

        int ans_t = 0;
        while (!q.isEmpty()) {
            int[] current = q.poll();
            int r = current[0];
            int c = current[1];
            int t = current[2];

            ans_t = Math.max(ans_t, t);

            if (r > 0 && matrix[r - 1][c] == 1 && !visited[r - 1][c]) {
                q.offer(new int[]{r - 1, c, t + 1});
                visited[r - 1][c] = true;
            }
            if (r + 1 < m && matrix[r + 1][c] == 1 && !visited[r + 1][c]) {
                q.offer(new int[]{r + 1, c, t + 1});
                visited[r + 1][c] = true;
            }
            if (c > 0 && matrix[r][c - 1] == 1 && !visited[r][c - 1]) {
                q.offer(new int[]{r, c - 1, t + 1});
                visited[r][c - 1] = true;
            }
            if (c + 1 < n && matrix[r][c + 1] == 1 && !visited[r][c + 1]) {
                q.offer(new int[]{r, c + 1, t + 1});
                visited[r][c + 1] = true;
            }
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (matrix[i][j] == 1 && !visited[i][j]) {
                    return -1;
                }
            }
        }

        return ans_t;
    }
}

