import java.util.*;

class Pair {
    int x;
    int y;
    int dist;

    Pair(int x, int y, int dist) {
        this.x = x;
        this.y = y;
        this.dist = dist;
    }
}

class Solution {
    public static int[][] nearestZero(int[][] grid) {
        int m = grid.length;
        int n = grid[0].length;

        int[][] ans = new int[m][n];
        boolean[][] visited = new boolean[m][n];
        Queue<Pair> q = new LinkedList<>();

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 0) {
                    q.add(new Pair(i, j, 0));
                    visited[i][j] = true;
                }
            }
        }

        while (!q.isEmpty()) {
            Pair p = q.poll();
            int r = p.x;
            int c = p.y;
            int d = p.dist;

            ans[r][c] = d;

            if (r > 0 && !visited[r - 1][c]) {
                q.add(new Pair(r - 1, c, d + 1));
                visited[r - 1][c] = true;
            }
            if (r + 1 < m && !visited[r + 1][c]) {
                q.add(new Pair(r + 1, c, d + 1));
                visited[r + 1][c] = true;
            }
            if (c > 0 && !visited[r][c - 1]) {
                q.add(new Pair(r, c - 1, d + 1));
                visited[r][c - 1] = true;
            }
            if (c + 1 < n && !visited[r][c + 1]) {
                q.add(new Pair(r, c + 1, d + 1));
                visited[r][c + 1] = true;
            }
        }

        return ans;
    }
}

