dfs(r, c, grid, visited) {
    /* Read the grid dimensions so neighbor checks stay inside bounds */
    m = grid.size()
    n = grid[0].size()

    /* Mark the current cell as safe because it is connected to the boundary */
    visited[r][c] = 1

    /* Move upward only when the next cell is valid, unvisited, and also O */
    if r > 0 && !visited[r - 1][c] && grid[r - 1][c] == 'O' {
        dfs(r - 1, c, grid, visited)
    }

    /* Move downward only when the next cell is valid, unvisited, and also O */
    if r + 1 < m && !visited[r + 1][c] && grid[r + 1][c] == 'O' {
        dfs(r + 1, c, grid, visited)
    }

    /* Move left only when the next cell is valid, unvisited, and also O */
    if c > 0 && !visited[r][c - 1] && grid[r][c - 1] == 'O' {
        dfs(r, c - 1, grid, visited)
    }

    /* Move right only when the next cell is valid, unvisited, and also O */
    if c + 1 < n && !visited[r][c + 1] && grid[r][c + 1] == 'O' {
        dfs(r, c + 1, grid, visited)
    }

    /* All connected safe cells from this position are now marked */
    return
}

surroundO(grid) {
    /* Read the grid dimensions once for all traversals */
    m = grid.size()
    n = grid[0].size()

    /* Create a matrix to remember which O cells are safe */
    visited[m][n] = {0}

    /* Check the top and bottom boundaries because those O cells cannot be surrounded */
    for j = 0 to n - 1 {
        /* Start DFS from an unvisited O on the top boundary */
        if grid[0][j] == 'O' && !visited[0][j] {
            dfs(0, j, grid, visited)
        }

        /* Start DFS from an unvisited O on the bottom boundary */
        if grid[m - 1][j] == 'O' && !visited[m - 1][j] {
            dfs(m - 1, j, grid, visited)
        }
    }

    /* Check the left and right boundaries for the remaining safe regions */
    for i = 1 to m - 2 {
        /* Start DFS from an unvisited O on the left boundary */
        if grid[i][0] == 'O' && !visited[i][0] {
            dfs(i, 0, grid, visited)
        }

        /* Start DFS from an unvisited O on the right boundary */
        if grid[i][n - 1] == 'O' && !visited[i][n - 1] {
            dfs(i, n - 1, grid, visited)
        }
    }

    /* Flip every inner O that was never marked as safe */
    for i = 1 to m - 2 {
        /* Scan every inner column of the current row */
        for j = 1 to n - 2 {
            /* This O is surrounded because it is not connected to any boundary O */
            if grid[i][j] == 'O' && !visited[i][j] {
                grid[i][j] = 'X'
            }
        }
    }

    /* The grid is updated in place */
    return
}
