class solution {
public:
    void dfs(int node, vector<int>& visited, vector<vector<pair<int, int>>>& adj, stack<int>& s) {
        visited[node] = 1;
        for (auto& k : adj[node]) {
            int neighbour = k.first;
            if (!visited[neighbour]) {
                dfs(neighbour, visited, adj, s);
            }
        }
        s.push(node);
    }

    vector<int> shortestPath(int n, int e, vector<vector<int>>& edges) {
        vector<int> visited(n, 0);
        vector<vector<pair<int, int>>> adj(n);

        for (auto& edge : edges) {
            adj[edge[0]].push_back({edge[1], edge[2]});
        }

        stack<int> s;
        dfs(0, visited, adj, s);

        vector<int> dist(n, INT_MAX);
        dist[0] = 0;

        while (!s.empty()) {
            int curr = s.top();
            s.pop();

            if (dist[curr] != INT_MAX) {
                for (auto& k : adj[curr]) {
                    int neighbour = k.first;
                    int weight = k.second;

                    if (dist[curr] + weight < dist[neighbour]) {
                        dist[neighbour] = dist[curr] + weight;
                    }
                }
            }
        }

        for (int i = 0; i < n; ++i) {
            if (dist[i] == INT_MAX) {
                dist[i] = -1;
            }
        }

        return dist;
    }
};

