class Solution {
    static shortestPath(n, e, edges, start) {
        const adj = Array.from({ length: n }, () => []);

        for (let i = 0; i < e; i++) {
            const a = edges[i][0];
            const b = edges[i][1];
            adj[a].push(b);
            adj[b].push(a);
        }

        const q = [start];
        let front = 0;

        const visited = new Array(n).fill(0);
        visited[start] = 1;

        const dist = new Array(n).fill(-1);
        dist[start] = 0;

        while (front < q.length) {
            const curr = q[front++];

            for (const k of adj[curr]) {
                if (!visited[k]) {
                    dist[k] = dist[curr] + 1;
                    visited[k] = 1;
                    q.push(k);
                }
            }
        }

        return dist;
    }
}

